// =====================
// RÉCUPÉRATION DES DONNÉES
// =====================
const perfAll = $('2022-2025').all();
const gptAll = $('Analyse_GPT5.1').all();

// Lignes 7+ = vidéos individuelles (index 5+)
const videos = perfAll.slice(5);

// =====================
// NETTOYAGE
// =====================
function cleanStr(s) {
  if (!s) return 'N/A';
  return String(s)
    .replace(/&amp;/g, '&')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\n/g, ' ')
    .trim();
}

// =====================
// 2A.1 — TITRES PAR ANNÉE
// =====================
const videosByYear = {};
videos.forEach(row => {
  const r = row.json;
  const date = cleanStr(r['Date']);
  const titre = cleanStr(r['Titre']);
  if (!titre || titre === 'N/A') return;

  // Extraire l'année
  let year = 'Inconnue';
  if (date && date.length >= 4) {
    year = date.substring(0, 4);
  }

  if (!videosByYear[year]) videosByYear[year] = [];
  videosByYear[year].push(titre);
});

// Trier les années décroissantes
const yearsSorted = Object.keys(videosByYear).sort((a, b) => b - a);

const titresParAnnee = yearsSorted.map(year => {
  const titres = videosByYear[year].map(t => `  - ${t}`).join('\n');
  return `${year} (${videosByYear[year].length} vidéos) :\n${titres}`;
}).join('\n\n');

const bloc2A1 = `=== TITRES PAR ANNÉE (lignes 7+) ===
${titresParAnnee}`;

// =====================
// 2A.2 — FORMATS ANALYSEGPT
// =====================
const formats = {};
gptAll.forEach(row => {
  const f = cleanStr(row.json['Format']);
  if (f && f !== 'N/A') {
    formats[f] = (formats[f] || 0) + 1;
  }
});

const formatsList = Object.entries(formats)
  .sort((a, b) => b[1] - a[1])
  .map(([f, count]) => `- ${f} : ${count}`)
  .join('\n');

const bloc2A2 = `=== FORMATS (AnalyseGPT — 15 vidéos) ===
${formatsList}`;

// =====================
// OUTPUT FINAL
// =====================
// Récupérer le nom de la chaîne depuis 2022-2025
const chaine = cleanStr(perfAll[0].json['Nom de la chaîne']);

return [{ json: {
  p2a_data: `${bloc2A1}\n\n${bloc2A2}`,
  chaine: chaine
}}];

// =====================
// RÉCUPÉRATION DES DONNÉES
// =====================
const infos = $('INFOS').first().json;
const perf = $('2022-2025').all();
const top15All = $('Top 15 vidéos').all();
const top15Totaux = top15All[0].json;

// =====================
// NETTOYAGE
// =====================
function cleanDate(d) {
  if (!d) return 'N/A';
  if (d.includes('T')) {
    return new Date(d).toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
  }
  return d;
}

function cleanStr(s) {
  if (!s) return 'N/A';
  return String(s).replace(/\n/g, ' ').trim();
}

function calcPoids(top15Vues, totalVues) {
  const pct = (top15Vues / totalVues * 100).toFixed(2);
  return `(${top15Vues} / ${totalVues} × 100 = ${pct}%)`;
}

// =====================
// 1.0 IDENTIFICATION
// =====================
const bloc10 = `## 1.0. Identification
Nom de la chaîne : ${cleanStr(infos['Nom de la chaîne'])}
Cluster : ${cleanStr(infos['Cluster'])}
Autorité LOG : ${cleanStr(infos['Autorité LOG'])}
Pays : ${cleanStr(infos['Pays'])}
Type de vélo : ${cleanStr(infos['Type de vélo'])}
Format : ${cleanStr(infos['Format'])}
Sujet : ${cleanStr(infos['Sujet'])}
Date de création : ${cleanDate(infos['Date de création'])}
Vol. abonnés : ${cleanStr(infos['Vol. abonnés'])}
Vues totales : ${cleanStr(infos['Vues totales'])}
Vol. vidéos : ${cleanStr(infos['Vol. vidéos'])}`;

// =====================
// 1.1 VOLUME & ACTIVITÉ
// =====================
const years = ['2022-2025', '2025', '2024', '2023', '2022'];
const agregats = perf.slice(0, 5).map(r => r.json);

const rows11 = agregats.map((r, i) => 
  `| ${years[i]} | ${r['Vol. vidéos annuel']} | ${r['Vues/video (moyenne annuelle)']} | ${r['Vues']} |`
).join('\n');

const bloc11 = `## 1.1. Volume & activité
| Année | Vol. vidéos | Vues/vidéo moyenne | Vues totales |
|:---|:---:|:---:|:---:|
${rows11}`;

// =====================
// 1.2 FORMATS & DURÉE
// =====================
const rows12 = agregats.map((r, i) =>
  `| ${years[i]} | ${r['Short ?']} | ${r['Durée']} |`
).join('\n');

const bloc12 = `## 1.2. Formats & durée
| Année | % Shorts | Durée moyenne |
|:---|:---:|:---:|
${rows12}`;

// =====================
// 1.3 ENGAGEMENT
// =====================
const rows13 = agregats.map((r, i) =>
  `| ${years[i]} | ${r['% likes/vues']} | ${r['% Engagement total']} | ${r['Vivacité (%commentaires/likes)']} |`
).join('\n');

const bloc13 = `## 1.3. Engagement
| Année | % likes/vues | % Engagement total | Vivacité |
|:---|:---:|:---:|:---:|
${rows13}`;

// =====================
// DONNÉES POUR GPT (1.4 + 1.5)
// =====================
const poidsCalc = calcPoids(top15Totaux['Vues'], infos['Vues totales']);

const top15Titres = top15All.slice(1, 16).map(row => {
  const r = row.json;
  return `- "${r['Titre']}" | ${r['Mois']} | Vues: ${r['Vues']} | Likes: ${r['Likes']} | Short: ${r['Short ?']}`;
}).join('\n');

const dataForGPT = `=== DONNÉES POUR 1.4 ET 1.5 ===

Poids du Top 15 : ${poidsCalc} des vues totales de la chaîne.

Top 15 titres :
${top15Titres}

Agrégats synthèse :
${agregats.map((r, i) => `${years[i]} : ${r['Vol. vidéos annuel']} vidéos | ${r['Vues/video (moyenne annuelle)']} vues/vidéo | ${r['Short ?']} Shorts | Durée: ${r['Durée']} | Engagement: ${r['% Engagement total']}% | Vivacité: ${r['Vivacité (%commentaires/likes)']}%`).join('\n')}`;

// =====================
// OUTPUT
// =====================
return [{ json: {
  blocs_code: `# P1. ID & PERFORMANCES\n\n${bloc10}\n\n${bloc11}\n\n${bloc12}\n\n${bloc13}`,
  data_for_gpt: dataForGPT,
  chaine: cleanStr(infos['Nom de la chaîne']),
  vues_totales: infos['Vues totales']
}}];

// =====================
// RÉCUPÉRATION
// =====================
const inputs = $input.all();
const top300Raw = $('Top 300 commentaires').all();
const infos = $('INFOS').first().json;

// =====================
// TRI PAR LIKES DÉCROISSANTS
// =====================
const top300 = [...top300Raw].sort((a, b) =>
  (Number(b.json['Likes']) || 0) - (Number(a.json['Likes']) || 0)
);

// =====================
// NETTOYAGE
// =====================
function decodeHTML(s) {
  if (!s) return '';
  return String(s)
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/&#\d+;/g, c => String.fromCharCode(parseInt(c.slice(2, -1))))
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/\n/g, ' ')
    .trim();
}

// =====================
// CHAÎNE
// =====================
const chaine = infos['Nom de la chaîne'] || 'N/A';
const chaineID = infos['ID'] || '';

const blocHeader = `=== CHAÎNE ANALYSÉE ===
Nom : ${chaine}
Handle YouTube : @${chaineID}
ATTENTION : Tout commentaire dont l'auteur correspond
à "${chaine}" ou "@${chaineID}" doit être ignoré —
c'est le créateur qui répond dans ses propres vidéos.

`;

// =====================
// TOP 3 PAR LIKES
// =====================
const top3 = top300.slice(0, 3).map((row, i) => {
  const r = row.json;
  return `${i + 1}. "${decodeHTML(r['TXT'])}" — Auteur: ${r['Auteur']} — Likes: ${r['Likes']}`;
}).join('\n');

const blocTop3 = `=== TOP 3 COMMENTAIRES PAR LIKES ===
${top3}`;

// =====================
// 300 COMMENTAIRES FORMATÉS
// =====================
const formatted = top300.map(row => {
  const r = row.json;
  return `TXT: ${decodeHTML(r['TXT'])} | Auteur: ${r['Auteur']} | Likes: ${r['Likes']} | Video ID: ${r['Video ID']}`;
}).join('\n');

const blocComments = `=== 300 COMMENTAIRES (triés par likes décroissants) ===
${formatted}`;

// =====================
// OUTPUT
// =====================
return [{ json: {
  p3_data: `${blocHeader}${blocTop3}\n\n${blocComments}`,
  YT_CHAINE: chaine
}}];

const input = $input.first().json;
const gptText = input.output[0].content[0].text;
const top300 = $('Top 300 commentaires').all();

// Récupérer le nom de la chaîne depuis INFOS
const chaine = $('INFOS').first().json['Nom de la chaîne'] || 'N/A';

// Extraire la section marques
const marquesSection = gptText.match(/Marques\/produits mentionnés\s*:\s*([\s\S]*?)(?=\n\n##)/);
const marquesRaw = marquesSection ? marquesSection[1] : '';

// Parser chaque ligne "Marque — @auteur1 ; @auteur2"
const lignes = marquesRaw.split('\n').filter(l => l.trim() && l.includes('—'));

const marquesVerifiees = [];
lignes.forEach(ligne => {
  const parts = ligne.split('—');
  if (parts.length < 2) return;
  const marque = parts[0].trim();
  const auteursReels = new Set(
    top300
      .filter(r => r.json['TXT'] &&
        r.json['TXT'].toLowerCase().includes(marque.toLowerCase()))
      .map(r => r.json['Auteur'])
  );
  if (auteursReels.size >= 2) {
    marquesVerifiees.push(`${marque} (${auteursReels.size} auteurs)`);
  }
});

const marquesFinales = marquesVerifiees.length > 0
  ? marquesVerifiees.join(', ')
  : 'N/A';

const p3Final = gptText.replace(
  /Marques\/produits mentionnés\s*:[\s\S]*?(?=\n\n##)/,
  `Marques/produits mentionnés : ${marquesFinales}\n\n`
);

return [{ json: {
  P3_Result: p3Final,
  YTchaine: chaine
}}];

const inputs = $input.all();

// Trouver les bons items par leur contenu
const p2aItem = inputs.find(i => i.json.output?.[0]?.content?.[0]?.text?.includes('2A. SUJETS'));
const p2bItem = inputs.find(i => i.json.output?.[0]?.content?.[0]?.text?.includes('2B. LIGNE'));
const chaineItem = inputs.find(i => i.json.chaine);

const p2aText = p2aItem.json.output[0].content[0].text;
const p2bText = p2bItem.json.output[0].content[0].text;
const chaine = chaineItem.json.chaine;

const p2Final = `${p2aText}\n\n---\n\n${p2bText}`;

return [{ json: {
  P2_Result: p2Final,
  YTchaine: chaine
}}];

const input = $input.first().json;
const gptText = input.output[0].content[0].text;

// Lire blocs_code depuis le nœud Edit Fields
const blocsCode = $('Edit Fields1').first().json.blocs_code;
const YTchaine = $('Edit Fields1').first().json.chaine;

const p1result= `${blocsCode}\n\n${gptText}`;

return [{ json: {
  P1_Result: p1result,
  YTchaine: YTchaine
}}];

const p1 = $('P1_Result').first().json.P1_Result;
const p2 = $('P2_Result').first().json.P2_Result;
const p3 = $('P3_Result').first().json.P3_Result;
const chaine = $('P1_Result').first().json.YTchaine;

const fullResult = `${p1}\n\n---\n\n${p2}\n\n---\n\n${p3}`;

return [{ json: {
  full_result: fullResult,
  YTchaine: chaine
}}];

const input = $input.first().json;
const content = input.full_result;
const chaine = input.YTchaine.replace(/\s+/g, '_');

const today = new Date();
const date = String(today.getDate()).padStart(2, '0')
  + String(today.getMonth() + 1).padStart(2, '0')
  + today.getFullYear();

const filename = `Folk_${chaine}_PDATA_${date}.md`;

const binaryData = Buffer.from(content, 'utf-8').toString('base64');

return [{
  json: { filename },
  binary: {
    file: {
      data: binaryData,
      mimeType: 'text/markdown',
      fileName: filename,
      fileExtension: 'md'
    }
  }
}];

// =====================
// RÉCUPÉRATION DES DONNÉES
// =====================
const gptAll = $('Analyse_GPT5.1').all();
const transAll = $('Transcription').all();
const perfAll = $('2022-2025').all();
const videos = perfAll.slice(5);

// =====================
// NETTOYAGE
// =====================
const mapping = {
  '茅': 'é', '脿': 'à', '猫': 'è', '么': 'ô',
  '卯': 'î', '莽': 'ç', '锚': 'ê', '毛': 'ë',
  '眉': 'ü', '脡': 'É', '脠': 'È', '脢': 'Ê',
  '脝': 'Æ', '脟': 'Ç'
};

function cleanStr(s) {
  if (!s) return 'N/A';
  let str = String(s)
    .replace(/&amp;/g, '&')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\n/g, ' ')
    .trim();
  for (const [bad, good] of Object.entries(mapping)) {
    str = str.split(bad).join(good);
  }
  return str;
}

// =====================
// ANALYSEGPT — captures + contexte + qualité
// =====================
const gptBlocs = gptAll.map(row => {
  const r = row.json;
  return `Video ID : ${cleanStr(r['Video ID'])}
Format : ${cleanStr(r['Format'])}
Humain : ${cleanStr(r['Humain'])}
Qualité prod. : ${cleanStr(r['Qualité prod.'])}
Contexte : ${cleanStr(r['Contexte'])}
Capture 25 : ${cleanStr(r['Capture 25'])}
Capture 50 : ${cleanStr(r['Capture 50'])}
Capture 75 : ${cleanStr(r['Capture 75'])}`;
}).join('\n\n---\n\n');

const blocGPT = `=== ANALYSEGPT (15 vidéos) ===
${gptBlocs}`;

// =====================
// TRANSCRIPTIONS
// =====================
const transBlocs = transAll.map(row => {
  const r = row.json;
  return `Video ID : ${cleanStr(r['Video ID'])}
Transcription : ${cleanStr(r['transcription'])}`;
}).join('\n\n---\n\n');

const blocTrans = `=== TRANSCRIPTIONS (15 vidéos) ===
${transBlocs}`;

// =====================
// DESCRIPTIONS YT (lignes 7+)
// =====================
const descBlocs = videos
  .filter(row => row.json['Description YT'] && row.json['Description YT'] !== 'x')
  .slice(0, 30) // limite à 30 pour ne pas surcharger
  .map(row => {
    const r = row.json;
    return `- "${cleanStr(r['Titre'])}" (${cleanStr(r['Date'])}) : ${cleanStr(r['Description YT'])}`;
  }).join('\n');

const blocDesc = `=== DESCRIPTIONS YT (extrait catalogue) ===
${descBlocs}`;

// =====================
// OUTPUT
// =====================
const chaine = cleanStr(perfAll[0].json['Nom de la chaîne']);

return [{ json: {
  p2b_data: `${blocGPT}\n\n${blocTrans}\n\n${blocDesc}`,
  chaine: chaine
}}];
